import{_ as o,o as e,c as l,ag as s}from"./chunks/framework.DXGyWiRo.js";const i="/media/202212/2022-12-19_155909_6971530.957385431346173.png",h=JSON.parse('{"title":"技能工作室概述","description":"","frontmatter":{"title":"技能工作室概述"},"headers":[],"relativePath":"custom-biz/skill-studio/overview.md","filePath":"custom-biz/skill-studio/overview.md","lastUpdated":null}'),r={name:"custom-biz/skill-studio/overview.md"};function a(n,t,p,c,d,u){return e(),l("div",null,[...t[0]||(t[0]=[s('<p><strong>目录</strong></p><ol><li>技能工作室简介</li><li>技能配置说明</li><li>技能开发步骤</li></ol><h2 id="技能工作室简介" tabindex="-1">技能工作室简介 <a class="header-anchor" href="#技能工作室简介" aria-label="Permalink to &quot;技能工作室简介&quot;">​</a></h2><p>技能工作室包含<strong>自定义技能</strong>、<strong>语句问答</strong>、<strong>关键词问答</strong>、<strong>设备人设</strong>，<strong>官方技能</strong>。 AIUI平台支持开发者免费开发私有技能、问答库、文档问答（大模型链路）。</p><h2 id="技能配置说明" tabindex="-1">技能配置说明 <a class="header-anchor" href="#技能配置说明" aria-label="Permalink to &quot;技能配置说明&quot;">​</a></h2><p>AIUI应用开启结构化语义后，可进行技能任意搭配设置。 按粒度划分：</p><ul><li>1个应用（设备）包含多个技能</li><li>1个技能包含多个意图</li><li>1个意图包含多个语料</li></ul><p><img src="'+i+'" alt="" title="null"></p><h2 id="私有技能开发步骤" tabindex="-1">私有技能开发步骤 <a class="header-anchor" href="#私有技能开发步骤" aria-label="Permalink to &quot;私有技能开发步骤&quot;">​</a></h2><ul><li><p>设计交互流程</p><p>先梳理客户或业务交互需求，整理后画一个流程图，描述用户请求和期望的结果；把请求抽象成<a href="/custom-biz/skill-studio/intents.html">意图</a>。可参考<a href="/custom-biz/skill-studio/voice-design-guide.html">技能设计规范</a>。</p></li><li><p>选择合适的实现方式 根据梳理业务方式选择合适的实现方式：自定义技能 、问答库，详细分类说明如下</p><ul><li>自定义技能-<strong>私有技能</strong>： 基于客户端私有业务进行流程业务编辑，能力强大，可实现复杂业务处理。技能构建发布无需讯飞审核，编写的技能发布后可在当前账号下所有应用下使用。</li><li>自定义技能-<strong>开放技能</strong>： 基于公开业务或创新业务实现技能开发，可实现复杂业务。该类型技能需要通过讯飞内部审核，通过后开放到官方技能类型下，可对AIUI所有用户开放。</li><li>自定义技能-<strong>定制技能</strong>： 当讯飞官方技能客户侧需要集成使用，但又有需求差异，如部分能力不支持或说法与实际需求有差异，可以基于官方技能做定制技能开发。</li><li>自定义问答库-<strong>语句问答</strong>： 当交互内容和回复都是明确的，如QA问答，可以直接创建语句问答库来实现。</li><li>自定义问答库-<strong>关键词问答</strong>： 当问题回复内容相对固定，问题查询需要做关键词匹配时，可以创建关键词问答实现。</li><li>自定义问答库-<strong>文档问答</strong>： 这是大模型提供的能力，当本地有相关知识文档，希望讯飞能基于这些文档做知识提取并满足交互问答，可以创建文档。该能力使用时需要开启交互大模型。</li></ul></li><li><p>在控制台创建技能 以简单的私有技能创建流程做演示，具体步操作可以<a href="/custom-biz/skill-studio/development/create.html">查看指引</a></p></li><li><p>完善技能的交互模型 将第1步的意图配置在技能中。完善用户语料。<a href="/custom-biz/skill-studio/development/intent-config.html">查看指引</a></p></li><li><p>技能逻辑处理 当语义理解识别意图后，你需要编码来满足用户的意图，支持 <strong>在线云函数</strong> 和 <strong>webhook</strong> 。当用户交互时，你的技能会收到讯飞服务器发送给你的 <code>Request</code>，你在接到<code>Request</code>之后进行处理并返回<code>Response</code>，讯飞将会根据返回的<code>Response</code>进行后续处理。<a href="/custom-biz/skill-studio/development/post-process.html">查看指引</a></p><p>使用 v2.1协议，查看<a href="/custom-biz/protocols/post-process-request-v21.html">2.1请求</a>和<a href="/custom-biz/protocols/post-process-response-v21.html">2.1回复</a>。</p></li><li><p>测试技能</p><p>技能发布前需测试并修复缺陷，<a href="/custom-biz/skill-studio/development/testing.html">查看指引</a></p></li><li><p>发布技能</p><p>私有技能可直接发布，并在应用中配置。<a href="/custom-biz/skill-studio/development/publish.html">查看指引</a></p></li></ul>',10)])])}const g=o(r,[["render",a]]);export{h as __pageData,g as default};
